m.SourceGeoFenceBaseId,
m.DestinationGeoFenceBaseId,
m.BaseFare,
  h1.Title AS DestinationGeoFenceBaseTitle,
  h2.Title AS SourceGeoFenceBaseTitle
FROM H_TransportFareByGeoFence m
  LEFT JOIN H_TransportGeoFenceBases h1 ON h1.Id = m.DestinationGeoFenceBaseId
  LEFT JOIN H_TransportGeoFenceBases h2 ON h2.Id = m.SourceGeoFenceBaseId;

