-- ===== transport.setup.fare-calculations (H_TransportFareCalculations) =====
DROP VIEW IF EXISTS Vi_SPC_FareCalculationListSummary;
CREATE OR REPLACE VIEW Vi_SPC_FareCalculationListSummary AS
SELECT
m.Id,
m.DistributorId,
m.CVOId,
m.TransportCategory,
m.ServiceCategory,
m.VehicleType,
m.ServiceClass,
m.CalculationItem,
m.CalculationType,
m.CalculateMethod,
m.CalculationPriority,
m.CalculationUnit,
m.UnitAmount,
m.Price,
m.PriceTable,
m.RecordKey,
m.CreatedAt_UTC,
m.CreatedBy,
m.ModifiedAt_UTC,
m.ModifiedBy,
m.RecordDeleted,
  h0e.Title AS DistributorTitle,
  h1e.Title AS CVOTitle
FROM H_TransportFareCalculations m
  LEFT JOIN H_Synced_Distributors h0 ON h0.Id = m.DistributorId
  LEFT JOIN H_AAA_Synced_EntityProfile h0e ON h0e.Id = h0.EntityId
  LEFT JOIN H_Synced_CVOs h1 ON h1.Id = m.CVOId
  LEFT JOIN H_AAA_Synced_EntityProfile h1e ON h1e.Id = h1.EntityId
WHERE m.RecordDeleted IS NULL;

DROP VIEW IF EXISTS Vi_SPC_FareCalculationProfile;
CREATE OR REPLACE VIEW Vi_SPC_FareCalculationProfile AS
SELECT
m.Id,
m.DistributorId,
m.CVOId,
m.TransportCategory,
m.ServiceCategory,
m.VehicleType,
m.ServiceClass,
m.CalculationItem,
m.CalculationType,
m.CalculateMethod,
m.CalculationPriority,
m.CalculationUnit,
m.UnitAmount,
m.Price,
m.PriceTable,
m.RecordKey,
m.CreatedAt_UTC,
m.CreatedBy,
m.ModifiedAt_UTC,
m.ModifiedBy,
m.RecordDeleted,
  h0e.Title AS DistributorTitle,
  h1e.Title AS CVOTitle
FROM H_TransportFareCalculations m
  LEFT JOIN H_Synced_Distributors h0 ON h0.Id = m.DistributorId
  LEFT JOIN H_AAA_Synced_EntityProfile h0e ON h0e.Id = h0.EntityId
  LEFT JOIN H_Synced_CVOs h1 ON h1.Id = m.CVOId
  LEFT JOIN H_AAA_Synced_EntityProfile h1e ON h1e.Id = h1.EntityId
WHERE m.RecordDeleted IS NULL;

